import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  // 상태 관리: 화면 표시용 URL과 서버 전송용 Blob 데이터
  const [imagePreview, setImagePreview] = useState(null);
  const [imageBlob, setImageBlob] = useState(null);

  // 1. 사진 촬영 함수
  const takePicture = async () => {
    try {
      const photo = await Camera.getPhoto({
        quality: 90, // 화질 (0~100)
        allowEditing: true, // 사진 촬영 후 편집 허용
        resultType: CameraResultType.Uri, // 파일의 경로(URI)를 받음
        source: CameraSource.Camera, // 앨범 대신 바로 카메라 실행
      });

      // 촬영한 사진을 화면에 보여주기 위해 경로 저장
      setImagePreview(photo.webPath);

      // 2. 서버 전송을 위한 바이너리(Blob) 데이터로 변환
      // photo.webPath에 있는 데이터를 fetch로 읽어와서 blob으로 바꿉니다.
      const response = await fetch(photo.webPath);
      const blob = await response.blob();
      setImageBlob(blob);
    } catch (error) {
      console.error("카메라 작동 오류:", error);
    }
  };

  // 3. 서버 전송 함수
  const uploadToServer = async () => {
    if (!imageBlob) {
      alert("먼저 사진을 촬영해주세요!");
      return;
    }

    // 파일 전송을 위한 FormData 객체 생성
    const formData = new FormData();
    // 'uploadFile'은 백엔드 API에서 설정한 필드 이름과 일치해야 합니다.
    formData.append("uploadFile", imageBlob, "captured_image.jpg");

    try {
      const response = await fetch("https://your-backend-api.com/upload", {
        method: "POST",
        body: formData,
        // 헤더(Content-Type)는 FormData를 사용할 때 브라우저가 자동으로 설정해줍니다.
      });

      if (response.ok) {
        alert("서버 전송에 성공했습니다! 🎉");
      } else {
        alert("전송 실패: " + response.status);
      }
    } catch (error) {
      console.error("네트워크 에러:", error);
      alert("서버와 통신할 수 없습니다.");
    }
  };

  return (
    <div style={containerStyle}>
      <h1>📸 앱 카메라 테스트</h1>

      <div style={previewBox}>
        {imagePreview ? (
          <img
            src={imagePreview}
            alt="Preview"
            style={{ width: "100%", borderRadius: "10px" }}
          />
        ) : (
          <p>촬영된 사진이 없습니다.</p>
        )}
      </div>

      <button onClick={takePicture} style={buttonStyle}>
        사진 촬영
      </button>
      <button
        onClick={uploadToServer}
        style={{ ...buttonStyle, backgroundColor: "#28a745" }}
      >
        서버로 전송
      </button>
    </div>
  );
}

// 스타일 설정 (간단한 인라인 스타일)
const containerStyle = {
  textAlign: "center",
  padding: "20px",
  backgroundColor: "#f9f9f9",
  minHeight: "100vh",
};
const previewBox = {
  width: "300px",
  height: "300px",
  border: "2px dashed #ccc",
  margin: "20px auto",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  overflow: "hidden",
};
const buttonStyle = {
  display: "block",
  width: "200px",
  padding: "15px",
  margin: "10px auto",
  fontSize: "16px",
  cursor: "pointer",
  borderRadius: "5px",
  border: "none",
  backgroundColor: "#007bff",
  color: "#fff",
  fontWeight: "bold",
};

export default App;
